INSERT INTO "infrastructure_cloudoperation" ("id", "session_id", "workspace_id", "operation_type", "status", "resource_type", "resource_name", "configuration", "error_message", "created_at", "updated_at", "workflow_id", "workflow_state", "message", "current_step", "environment", "domain_name", "custom_domain_name", "alternate_domain_names", "application_files_storage", "ssl_certificate_arn", "ssl_certificate_status", "dns_records", "dns_provider", "dns_zone_id", "cloud_provider", "cloud_region", "cloud_account_id", "kubernetes_namespace", "kubernetes_cluster", "kubernetes_context", "kubeernetes_miscelaneous", "kubernetes_reserved_field_1", "kubernetes_reserved_field_2", "kubernetes_reserved_field_3", "kubernetes_reserved_field_4", "kubernetes_reserved_field_5", "kubernetes_reserved_list_1", "kubernetes_reserved_list_2", "kubernetes_reserved_list_3", "state_facts", "reports", "state_path", "state_backend", "state_backend_source", "state_bucket", "state_key", "source_code", "source_code_hash", "source_code_format", "ai_risk_assessment", "ai_completion_prediction", "ai_code_adopted", "user_modification_details", "query_terms", "inputs", "search_keys", "search_results", "ai_model_editable_field_1", "ai_model_editable_field_2", "ai_model_editable_field_3", "ai_model_editable_field_4", "ai_model_editable_field_5", "ai_model_editable_field_6", "web_hosting_params_1", "web_hosting_params_2", "web_hosting_params_3", "web_hosting_params_6", "web_hosting_params_9", "extended_editable_field_1", "extended_editable_field_2", "extended_editable_field_3", "extended_editable_field_4", "extended_editable_field_5", "extended_boolean_field_1", "extended_boolean_field_2", "extended_boolean_field_3", "extended_boolean_field_4", "extended_boolean_field_5", "extended_json_field_1", "extended_json_field_2", "extended_json_field_3", "extended_json_field_4", "extended_json_field_5", "extended_json_field_6", "extended_json_field_7", "extended_json_field_8", "extended_json_field_9", "extended_json_field_10") VALUES ('d8304d1b-8e35-4205-8477-4a1cc1770d85', '1d088d2a-995e-432c-ae04-74fd1f988703', '97daf056-5422-4bf3-9db7-5d3ab74d56e0', 'PROVISION', 'IN_PROGRESS', 'iam_user', 'testuse120001', '{"tags": {"CreatedBy": "frontend", "ManagedBy": "Terraform", "Environment": "development"}, "groups": [], "region": "us-east-1", "user_path": "/", "create_user": true, "policy_arns": [], "resource_name": "testuse120001", "resource_type": "iam_user", "cloud_provider": "aws", "attach_policies": false, "password_length": 20, "create_access_key": false, "create_login_profile": false, "password_reset_required": true, "store_credentials_in_ssm": false}', NULL, '2026-01-24T07:55:27.780552+00:00', '2026-01-24T07:55:28.271616+00:00', NULL, NULL, 'Starting Terraform initialization...', 50, 'PRODUCTION', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'aws', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '# This is the main.tf file for AWS IAM User provisioning.
# It creates IAM users with customizable configurations.
# It supports creating users with console access, programmatic access, and group memberships.

############################################################
# ── VARIABLES ───────────────────────────────────────────
############################################################

variable "aws_region" {
  type        = string
  description = "AWS region where the IAM resources will be created"
}

variable "create_user" {
  type        = bool
  default     = true
  description = "Whether to create an IAM user"
}

variable "user_name" {
  type        = string
  description = "Name of the IAM user"
}

variable "user_path" {
  type        = string
  default     = "/"
  description = "Path of the IAM user"
}

variable "user_permissions_boundary" {
  type        = string
  default     = null
  description = "ARN of the policy that is used to set the permissions boundary for the user"
}

variable "user_force_destroy" {
  type        = bool
  default     = true
  description = "When destroying this user, destroy even if it has non-Terraform-managed IAM access keys, login profile or MFA devices"
}

# Console Access
variable "create_login_profile" {
  type        = bool
  default     = false
  description = "Whether to create IAM user login profile (console access)"
}

variable "password_length" {
  type        = number
  default     = 20
  description = "The length of the generated password"
}

variable "password_reset_required" {
  type        = bool
  default     = true
  description = "Whether the user should be forced to reset the generated password on first login"
}

# Programmatic Access
variable "create_access_key" {
  type        = bool
  default     = false
  description = "Whether to create IAM access key"
}

variable "access_key_status" {
  type        = string
  default     = "Active"
  description = "Access key status to apply (Active or Inactive)"
}

# Store credentials in SSM
variable "store_credentials_in_ssm" {
  type        = bool
  default     = false
  description = "Whether to store the access keys in AWS SSM Parameter Store"
}

variable "ssm_parameter_prefix" {
  type        = string
  default     = "/iam-users/"
  description = "Prefix for SSM parameters when storing credentials"
}

# Group Memberships
variable "groups" {
  type        = list(string)
  default     = []
  description = "List of IAM groups to add the user to"
}

# Policy Attachments
variable "attach_policies" {
  type        = bool
  default     = false
  description = "Whether to attach policies to the user"
}

variable "policy_arns" {
  type        = list(string)
  default     = []
  description = "List of policy ARNs to attach to the user"
}

# Inline Policy
variable "create_inline_policy" {
  type        = bool
  default     = false
  description = "Whether to create an inline policy for the user"
}

variable "inline_policy_name" {
  type        = string
  default     = ""
  description = "Name of the inline policy"
}

variable "inline_policy_document" {
  type        = string
  default     = ""
  description = "JSON policy document for the inline policy"
}

variable "tags" {
  type        = map(string)
  default     = {}
  description = "Tags to apply to the IAM resources"
}

############################################################
# ── PROVIDER ────────────────────────────────────────────
############################################################

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

############################################################
# ── RANDOM PASSWORD ─────────────────────────────────────
############################################################

resource "random_password" "user_password" {
  count = var.create_user && var.create_login_profile ? 1 : 0

  length           = var.password_length
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

############################################################
# ── IAM USER ────────────────────────────────────────────
############################################################

resource "aws_iam_user" "this" {
  count = var.create_user ? 1 : 0

  name                 = var.user_name
  path                 = var.user_path
  permissions_boundary = var.user_permissions_boundary
  force_destroy        = var.user_force_destroy

  tags = var.tags
}

############################################################
# ── LOGIN PROFILE (Console Access) ──────────────────────
############################################################

resource "aws_iam_user_login_profile" "this" {
  count = var.create_user && var.create_login_profile ? 1 : 0

  user                    = aws_iam_user.this[0].name
  password_length         = var.password_length
  password_reset_required = var.password_reset_required

  lifecycle {
    ignore_changes = [password_length, password_reset_required]
  }
}

############################################################
# ── ACCESS KEY (Programmatic Access) ────────────────────
############################################################

resource "aws_iam_access_key" "this" {
  count = var.create_user && var.create_access_key ? 1 : 0

  user   = aws_iam_user.this[0].name
  status = var.access_key_status
}

############################################################
# ── SSM PARAMETERS (Credential Storage) ─────────────────
############################################################

resource "aws_ssm_parameter" "access_key_id" {
  count = var.create_user && var.create_access_key && var.store_credentials_in_ssm ? 1 : 0

  name        = "${var.ssm_parameter_prefix}${var.user_name}/access_key_id"
  description = "Access Key ID for IAM user ${var.user_name}"
  type        = "SecureString"
  value       = aws_iam_access_key.this[0].id

  tags = var.tags
}

resource "aws_ssm_parameter" "secret_access_key" {
  count = var.create_user && var.create_access_key && var.store_credentials_in_ssm ? 1 : 0

  name        = "${var.ssm_parameter_prefix}${var.user_name}/secret_access_key"
  description = "Secret Access Key for IAM user ${var.user_name}"
  type        = "SecureString"
  value       = aws_iam_access_key.this[0].secret

  tags = var.tags
}

resource "aws_ssm_parameter" "user_password" {
  count = var.create_user && var.create_login_profile && var.store_credentials_in_ssm ? 1 : 0

  name        = "${var.ssm_parameter_prefix}${var.user_name}/password"
  description = "Console password for IAM user ${var.user_name}"
  type        = "SecureString"
  value       = aws_iam_user_login_profile.this[0].password

  tags = var.tags
}

############################################################
# ── GROUP MEMBERSHIPS ───────────────────────────────────
############################################################

resource "aws_iam_user_group_membership" "this" {
  count = var.create_user && length(var.groups) > 0 ? 1 : 0

  user   = aws_iam_user.this[0].name
  groups = var.groups
}

############################################################
# ── POLICY ATTACHMENTS ──────────────────────────────────
############################################################

resource "aws_iam_user_policy_attachment" "this" {
  count = var.create_user && var.attach_policies ? length(var.policy_arns) : 0

  user       = aws_iam_user.this[0].name
  policy_arn = var.policy_arns[count.index]
}

############################################################
# ── INLINE POLICY ───────────────────────────────────────
############################################################

resource "aws_iam_user_policy" "this" {
  count = var.create_user && var.create_inline_policy && var.inline_policy_document != "" ? 1 : 0

  name   = var.inline_policy_name != "" ? var.inline_policy_name : "${var.user_name}-inline-policy"
  user   = aws_iam_user.this[0].name
  policy = var.inline_policy_document
}

############################################################
# ── OUTPUTS ─────────────────────────────────────────────
############################################################

output "user_name" {
  description = "Name of the IAM user"
  value       = var.create_user ? aws_iam_user.this[0].name : null
}

output "user_arn" {
  description = "ARN of the IAM user"
  value       = var.create_user ? aws_iam_user.this[0].arn : null
}

output "user_id" {
  description = "Unique ID of the IAM user"
  value       = var.create_user ? aws_iam_user.this[0].unique_id : null
}

output "user_path" {
  description = "Path of the IAM user"
  value       = var.create_user ? aws_iam_user.this[0].path : null
}

output "access_key_id" {
  description = "The access key ID"
  value       = var.create_user && var.create_access_key ? aws_iam_access_key.this[0].id : null
  sensitive   = true
}

output "secret_access_key" {
  description = "The secret access key"
  value       = var.create_user && var.create_access_key ? aws_iam_access_key.this[0].secret : null
  sensitive   = true
}

output "user_password" {
  description = "The generated password for console access"
  value       = var.create_user && var.create_login_profile ? aws_iam_user_login_profile.this[0].password : null
  sensitive   = true
}

output "console_login_url" {
  description = "AWS Console login URL for the IAM user"
  value       = var.create_user && var.create_login_profile ? "https://console.aws.amazon.com/" : null
}

output "groups" {
  description = "List of groups the user is a member of"
  value       = var.create_user && length(var.groups) > 0 ? var.groups : []
}

output "attached_policies" {
  description = "List of policy ARNs attached to the user"
  value       = var.create_user && var.attach_policies ? var.policy_arns : []
}

