tp://localhost:8000/health\"\n          \u001b[32m+\u001b[0m\u001b[0m http_port    = 80\n          \u001b[32m+\u001b[0m\u001b[0m url          = \"http://localhost:8000\"\n          \u001b[32m+\u001b[0m\u001b[0m web_port     = 8000\n        }\n    }\n  \u001b[32m+\u001b[0m\u001b[0m ssh_username  = \"ubuntu\"\n  \u001b[32m+\u001b[0m\u001b[0m web_app_url   = \"http://localhost:8000\"\n  \u001b[32m+\u001b[0m\u001b[0m web_port      = 8000\n\u001b[90m\n\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u001b[0m\n\nSaved the plan to: tfplan\n\nTo perform exactly these actions, run the following command to apply:\n    terraform apply \"tfplan\"\n[SUCCESS] Terraform plan completed\n[INFO] Executing: terraform apply -auto-approve\n\nTerraform used the selected providers to generate the following execution\nplan. Resource actions are indicated with the following symbols:\n  \u001b[32m+\u001b[0m create\u001b[0m\n \u001b[36m<=\u001b[0m read (data resources)\u001b[0m\n\nTerraform will perform the following actions:\n\n\u001b[1m  # data.local_file.prerequisites_check_results\u001b[0m will be read during apply\n  # (depends on a resource or a module with changes pending)\n\u001b[0m \u001b[36m<=\u001b[0m\u001b[0m data \"local_file\" \"prerequisites_check_results\" {\n      \u001b[32m+\u001b[0m\u001b[0m content              = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha256 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha512 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_md5          = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha1         = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha256       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha512       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m filename             = \"./bin/prerequisites_check_results.txt\"\n      \u001b[32m+\u001b[0m\u001b[0m id                   = (known after apply)\n    }\n\n\u001b[1m  # data.local_file.provisioner_results\u001b[0m will be read during apply\n  # (depends on a resource or a module with changes pending)\n\u001b[0m \u001b[36m<=\u001b[0m\u001b[0m data \"local_file\" \"provisioner_results\" {\n      \u001b[32m+\u001b[0m\u001b[0m content              = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha256 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha512 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_md5          = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha1         = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha256       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha512       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m filename             = \"./bin/provisioner_status.json\"\n      \u001b[32m+\u001b[0m\u001b[0m id                   = (known after apply)\n    }\n\n\u001b[1m  # local_file.docker_compose\u001b[0m will be created\n\u001b[0m  \u001b[32m+\u001b[0m\u001b[0m resource \"local_file\" \"docker_compose\" {\n      \u001b[32m+\u001b[0m\u001b[0m content              = <<-EOT\n            version: ''3.8''\n            \n            services:\n              nginx:\n                build:\n                  context: ./nginx\n                  dockerfile: Dockerfile\n                  args:\n                    - APP_PORT=8000\n                    - HTTP_PORT=80\n                container_name: nginx-fastapi\n                ports:\n                  - \"80:80\"\n                environment:\n                  - app_name=fastapi\n                  - app_port=8000\n                depends_on:\n                  - fastapi\n                networks:\n                  - fastapi-network\n                volumes:\n                  - type: volume\n                    source: nginx-logs\n                    target: /var/log/nginx\n            \n              fastapi:\n                build:\n                  context: ./app\n                  dockerfile: Dockerfile\n                container_name: fastapi\n                image: fastapi:latest\n                ports:\n                  - \"8000:8000\"\n                networks:\n                  - fastapi-network\n                healthcheck:\n                  test: [\"CMD\", \"curl\", \"-f\", \"http://localhost:8000/health\"]\n                  interval: 30s\n                  timeout: 10s\n                  retries: 3\n                  start_period: 5s\n                volumes:\n                  - type: volume\n                    source: fastapi-data\n                    target: /app/data\n            \n            networks:\n              fastapi-network:\n                driver: bridge\n            \n            volumes:\n              nginx-logs:\n                driver: local\n              fastapi-data:\n                driver: local\n        EOT\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha256 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha512 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_md5          = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha1         = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha256       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha512       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m directory_permission = \"0777\"\n      \u001b[32m+\u001b[0m\u001b[0m file_permission      = \"0777\"\n      \u001b[32m+\u001b[0m\u001b[0m filename             = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m id                   = (known after apply)\n    }\n\n\u001b[1m  # local_file.entrypoint_script\u001b[0m will be created\n\u001b[0m  \u001b[32m+\u001b[0m\u001b[0m resource \"local_file\" \"entrypoint_script\" {\n      \u001b[32m+\u001b[0m\u001b[0m content              = <<-EOT\n            #!/bin/bash\n            \n            # entrypoint.sh for for any of our Docker Compose\n            # Enhanced with container management and monitoring utilities\n            \n            # Configuration\n            LOG_FILE=\"/var/log/container-manager.log\"\n            MAX_LOG_SIZE_MB=10\n            MAX_LOG_FILES=5\n            \n            # Initialize logging\n            setup_logging() {\n                # Try to setup logging, but don''t fail if we can''t write to /var/log\n                if mkdir -p \"$(dirname \"$LOG_FILE\")\" 2>/dev/null && touch \"$LOG_FILE\" 2>/dev/null; then\n                    exec > >(tee -a \"$LOG_FILE\" 2>/dev/null) 2>&1\n                else\n                    # Fallback to stdout/stderr if we can''t write to log file\n                    exec > >(tee -a /tmp/container-manager.log 2>/dev/null || cat) 2>&1\n                fi\n                echo \"[$(date)] Starting container management\"\n            }\n            \n            # Rotate logs if they get too large\n            rotate_logs() {\n                local log_file=\"${LOG_FILE:-/tmp/container-manager.log}\"\n                if [ -f \"$log_file\" ]; then\n                    local size_mb=$(du -m \"$log_file\" 2>/dev/null | cut -f1 || echo \"0\")\n                    if [ \"$size_mb\" -gt \"$MAX_LOG_SIZE_MB\" ] 2>/dev/null; then\n                        for i in $(seq $((MAX_LOG_FILES-1)) -1 1); do\n                            if [ -f \"${log_file}.${i}\" ]; then\n                                mv -f \"${log_file}.${i}\" \"${log_file}.$((i+1))\" 2>/dev/null || true\n                            fi\n                        done\n                        mv \"$log_file\" \"${log_file}.1\" 2>/dev/null || true\n                    fi\n                fi\n            }\n            \n            # Handle termination signals\n            trap ''handle_termination'' SIGTERM SIGINT\n            \n            handle_termination() {\n                echo \"[$(date)] Received termination signal. Cleaning up...\"\n                cleanup_resources\n                exit 0\n            }\n            \n            # Clean up resources\n            cleanup_resources() {\n                echo \"Cleaning up resources...\"\n                docker system prune -f --volumes\n            }\n            \n            # Validate required environment variables\n            validate_environment() {\n                local required_vars=(\"app_name\" \"app_port\")\n                local missing_vars=()\n                \n                for var in \"${required_vars[@]}\"; do\n                    eval \"value=\\$$$$${var}\"\n                    if [ -z \"$value\" ]; then\n                        missing_vars+=(\"$var\")\n                    fi\n                done\n                \n                if [ ${#missing_vars[@]} -ne 0 ]; then\n                    echo \"Warning: Missing environment variables: ${missing_vars[*]}\" >&2\n                    echo \"Using defaults: app_name=redis, app_port=6379\" >&2\n                    app_name=\"fastapi\"\n                    app_port=\"8000\"\n                fi\n            }\n            \n            # Function to check container resource usage\n            check_container_resources() {\n                local container=$1\n                if [ -z \"$container\" ]; then\n                    return 0\n                fi\n                echo \"[$(date)] Checking resource usage for $container...\"\n                docker stats --no-stream \"$container\" 2>/dev/null || true\n                \n                # Check container resource limits (non-fatal)\n                local mem_limit=$(docker inspect \"$container\" --format ''{{.HostConfig.Memory}}'' 2>/dev/null || echo \"\")\n                local cpu_quota=$(docker inspect \"$container\" --format ''{{.HostConfig.CpuQuota}}'' 2>/dev/null || echo \"\")\n                echo \"Container $container - Memory Limit: ${mem_limit:-''No limit''}, CPU Quota: ${cpu_quota:-''No limit''}\"\n            }\n            \n            # Function to check container logs\n            check_container_logs() {\n                local container=$1\n                local lines=${2:-10}\n                if [ -z \"$container\" ]; then\n                    return 0\n                fi\n                echo \"[$(date)] Last $lines log lines for $container:\"\n                docker logs --tail $lines \"$container\" 2>/dev/null || true\n                \n                # Check for error patterns in logs (non-fatal)\n                local error_count=$(docker logs \"$container\" 2>&1 | grep -i -E ''error|fail|exception|timeout'' | wc -l || echo \"0\")\n                if [ \"$error_count\" -gt 0 ] 2>/dev/null; then\n                    echo \"WARNING: Found $error_count potential error(s) in $container logs\"\n                    return 1\n                fi\n                return 0\n            }\n            \n            # Function to check container health\n            check_container_health() {\n                local container=$1\n                if [ -z \"$container\" ]; then\n                    return 0\n                fi\n                local health_status=$(docker inspect --format=''{{.State.Health.Status}}'' \"$container\" 2>/dev/null || echo \"\")\n                \n                if [ \"$health_status\" = \"healthy\" ]; then\n                    echo \"\u2705 Container $container is healthy\"\n                    return 0\n                elif [ -n \"$health_status\" ]; then\n                    echo \"\u26a0\ufe0f  Container $container health status: $health_status\"\n                    return 0  # Don''t fail, just warn\n                else\n                    echo \"\u2139\ufe0f  No health check configured for $container\"\n                    return 0\n                fi\n            }\n            \n            # Function to check container networking\n            check_container_networking() {\n                local container=$1\n                if [ -z \"$container\" ]; then\n                    return 0\n                fi\n                echo \"[$(date)] Checking network configuration for $container...\"\n                docker inspect -f ''{{range .NetworkSettings.Networks}}{{.IPAddress}}{{end}}'' \"$container\" 2>/dev/null | xargs -I {} echo \"IP Address: {}\" || true\n                docker inspect -f ''{{range $p, $conf := .NetworkSettings.Ports}} {{$p}} -> {{(index $conf 0).HostPort}} {{end}}'' \"$container\" 2>/dev/null | xargs -I {} echo \"Port Mappings: {}\" || true\n            }\n            \n            # Function to check container volumes\n            check_container_volumes() {\n                local container=$1\n                if [ -z \"$container\" ]; then\n                    return 0\n                fi\n                echo \"[$(date)] Checking volumes for $container...\"\n                docker inspect -f ''{{range .Mounts}}{{.Type}} {{.Source}} -> {{.Destination}} ({{.Mode}})\\n{{end}}'' \"$container\" 2>/dev/null || true\n            }\n            \n            # Function to check if a port is in use and remove conflicting containers\n            check_port() {\n                local port=$1\n                echo \"[$(date)] Checking port $port...\"\n                if lsof -i :$port > /dev/null 2>&1; then\n                    echo \"Port $port is already in use. Attempting to free it...\"\n                    \n                    # First, try to find and remove any Docker containers using this port\n                    local conflicting_containers=$(docker ps -a -q | xargs -r docker inspect -f ''{{.Name}} {{.NetworkSettings.Ports}}'' 2>/dev/null | grep \":$port\" | cut -d'' '' -f1 | sed ''s/^.//'')\n                    \n                    if [ -n \"$conflicting_containers\" ]; then\n                        echo \"Found conflicting containers: $conflicting_containers\"\n                        echo \"Removing conflicting containers...\"\n                        echo \"$conflicting_containers\" | xargs -r docker rm -f\n                    fi\n                    \n                    # If port is still in use, find and kill the processes\n                    if lsof -i :$port > /dev/null 2>&1; then\n                        echo \"Port $port still in use. Finding processes...\"\n                        local pids=$(lsof -ti :$port)\n                        if [ -n \"$pids\" ]; then\n                            echo \"Killing processes using port $port: $pids\"\n                            echo \"$pids\" | xargs -r kill -9\n                            sleep 2\n                            \n                            # Final check\n                            if lsof -i :$port > /dev/null 2>&1; then\n                                echo \"WARNING: Port $port is still in use after cleanup attempts\"\n                                return 1\n                            else\n                                echo \"Port $port successfully freed\"\n                            fi\n                        fi\n                    fi\n                else\n                    echo \"Port $port is available\"\n                fi\n                return 0\n            }\n            \n            # Initialize results JSON\n            results=''{\"status\":\"unknown\", \"container_status\":[], \"logs\":{}, \"errors\":[]}''\n            \n            # Setup logging and validate environment\n            setup_logging\n            rotate_logs\n            validate_environment\n            \n            # Check and clear ports for the application if needed\n            if [ -n \"8000\" ]; then\n                if ! check_port \"8000\"; then\n                    results=$(echo \"$results\" | jq --arg port \"8000\" ''.status = \"warning\" | .errors += [\"Port \" + $port + \" is in use\"]'' 2>/dev/null || echo \"$results\")\n                    echo \"[$(date)] Warning: Port 8000 check had issues, but continuing...\"\n                fi\n            else\n                echo \"[$(date)] Warning: app_port not set, skipping port check\"\n            fi\n            \n            \n            # Wait for the application to be ready (container app)\n            app_name=\"fastapi\"\n            echo \"[$(date)] Waiting for fastapi (container app) to be ready...\"\n            max_attempts=10\n            attempt=1\n            app_ready=false\n            \n            # First, try to find container by name pattern (e.g., redis-server, redis, etc.)\n            container_name=\"\"\n            for name in \"fastapi\" \"fastapi-server\" \"redis-server\" \"redis\"; do\n                if docker ps --format ''{{.Names}}'' | grep -q \"^${name}$\" 2>/dev/null; then\n                    container_name=\"${name}\"\n                    break\n                fi\n            done\n            \n            # If no exact match, get first running container\n            if [ -z \"$container_name\" ]; then\n                container_name=$(docker ps --format ''{{.Names}}'' | head -1)\n            fi\n            \n            if [ -n \"$container_name\" ]; then\n                while [ $attempt -le $max_attempts ]; do\n                    # Check if container is running\n                    if docker inspect -f ''{{.State.Running}}'' \"$container_name\" > /dev/null 2>&1; then\n                        echo \"[$(date)] \u2705 ${container_name} is running!\"\n                        \n                        # Perform additional checks (non-fatal)\n                        check_container_health \"$container_name\" || true\n                        check_container_networking \"$container_name\" || true\n                        check_container_volumes \"$container_name\" || true\n                        check_container_resources \"$container_name\" || true\n                        check_container_logs \"$container_name\" 5 || true\n                        \n                        app_ready=true\n                        break\n                    fi\n                    echo \"[$(date)] Attempt $attempt/$max_attempts: ${container_name} not ready yet...\"\n                    sleep 2\n                    attempt=$((attempt + 1))\n                done\n            fi\n            \n            if [ \"$app_ready\" = false ]; then\n                echo \"[$(date)] \u26a0\ufe0f  Warning: fastapi not found or not ready, but checking all containers...\"\n                docker ps || true\n                # Don''t exit with error, just log warning\n                results=$(echo \"$results\" | jq ''.status = \"warning\" | .errors += [\"Container check had issues\"]'' 2>/dev/null || echo \"$results\")\n            fi\n            \n            # Final status check and health verification\n            echo -e \"\\n[$(date)] Final Container Status:\"\n            container_status=$(docker ps --format \"{{.Names}}\\t{{.Status}}\\t{{.Ports}}\" 2>/dev/null || echo \"No containers running\")\n            echo \"$container_status\"\n            \n            # Get detailed container information (non-fatal)\n            container_info=$(docker ps --format ''{{.Names}}'' 2>/dev/null | head -1 | xargs -I {} bash -c ''docker inspect -f \"{{.State.Status}} (Health: {{.State.Health.Status}})\" {} 2>/dev/null || echo \"unknown\"'' || echo \"No containers\")\n            \n            # Update results with detailed information (non-fatal)\n            if command -v jq >/dev/null 2>&1; then\n                results=$(echo \"$results\" | jq --arg status \"$container_status\" --arg info \"$container_info\" \\\n                    ''.container_status = $status | .container_info = $info | .status = \"success\"'' 2>/dev/null || echo \"$results\")\n            else\n                results=''{\"status\":\"success\",\"message\":\"Container validation completed\"}''\n            fi\n            \n            # Output final status\n            echo -e \"\\n[$(date)] \u2705 Validation completed!\"\n            \n            # Display container information if available\n            if [ -n \"$container_info\" ] && [ \"$container_info\" != \"No containers\" ]; then\n                echo -e \"\\nContainer Details:\"\n                echo \"$container_info\"\n            fi\n            \n            # Output final results (simple JSON)\n            echo -e \"\\n[$(date)] Deployment Summary:\"\n            echo \"$results\" | head -5\n            \n            # Clean up old logs (non-fatal)\n            rotate_logs || true\n            \n            exit 0\n        EOT\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha256 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_base64sha512 = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_md5          = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha1         = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha256       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m content_sha512       = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m directory_permission = \"0777\"\n      \u001b[32m+\u001b[0m\u001b[0m file_permission      = \"0755\"\n      \u001b[32m+\u001b[0m\u001b[0m filename             = (known after apply)\n      \u001b[32m+\u001b[0m\u001b[0m id                   = (known after apply)\n    }\n\n\u001b[1m  # null_resource.check_prerequisites\u001b[0m will b