############################################################
# ── VARIABLES ─────────────────────────────────────────────
############################################################
variable "resource_name" {
  type    = string
  default = "valtunox-tenant-instance"
}

variable "tenant_instance_type" {
  type    = string
  default = "t2.micro"
}

variable "tenant_environment" {
  type    = string
  default = "development"
}

variable "tenant_os" {
  type    = string
  default = "Ubuntu 20.04 LTS"
}

variable "company_name" {
  type    = string
  default = "valtunox"
}

variable "tenant_instance_volume_size" {
  type    = number
  default = 30
}

variable "tenant_instance_volume_type" {
  type    = string
  default = "gp3"
}

variable "publicip" {
  type    = bool
  default = true
}

variable "create_vpc" {
  type    = bool
  default = true
}

variable "existing_public_subnet_id" {
  type    = string
  default = ""
}

variable "workspace_id" {
  type    = string
  default = ""
}

variable "instance_type" {
  type    = string
  default = ""
}

variable "ami_id" {
  type    = string
  default = ""
}


variable "subnet_id" {
  type    = string
  default = ""
}

variable "vpc_id" {
  type    = string
  default = ""
}

variable "security_group_ids" {
  type    = list(string)
  default = ["sg-12345678"]
}

variable "tags" {
  type = map(string)
  default = {
    Environment = "development"
    Managed_by  = "terraform"
    Project     = "valtunox"
    Company     = "valtunox"
    Category    = "general"
    License     = "community"
  }
}

# --- Added for undeclared variables ---
variable "workspace_name" {
  type        = string
  default     = "valtunox"
  description = "Name of the workspace, if used in terraform.auto.tfvars"
}

variable "existing_security_group_id" {
  type        = string
  default     = ""
  description = "ID of an existing security group, if used in terraform.auto.tfvars"
}

# Add variables for optional SSH key overrides
variable "private_key_ssh" {
  type        = string
  default     = ""
  description = "Optional: Provide a PEM private key. If empty, a new key will be generated."
}
variable "public_key_ssh" {
  type        = string
  default     = ""
  description = "Optional: Provide a public key. If empty, a new key will be generated."
}
variable "vm_ssh_private_key_base64" {
  type        = string
  default     = ""
  description = "Optional: Provide a base64-encoded PEM. If empty, a new key will be generated."
}
variable "key_pair_name" {
  type        = string
  default     = ""
  description = "Optional: Provide a key pair name. If empty, will use resource_name."
}

variable "public_ip_base" {
  type        = string
  default     = "200.100.20"
  description = "Base IP address for public IP (format: x.x.x, e.g., 200.100.20)"
}

variable "private_ip_base" {
  type        = string
  default     = "10.0.0"
  description = "Base IP address for private IP (format: x.x.x, e.g., 10.0.0)"
}

############################################################
# ── LOCALS ────────────────────────────────────────────────
############################################################
locals {
  # Add timestamp to force recreation on every apply if needed
  timestamp = timestamp()

  # Define static values for simplicity, as we are no longer reading from vms.json
  # These can be replaced with random_string or random_id resources if more randomness is desired.
  mock_state = "running"
  mock_type  = var.tenant_instance_type # Use the variable default for type
  mock_az    = "us-east-1a"             # Example Availability Zone

  effective_key_pair_name             = trimspace(var.key_pair_name) != "" ? trimspace(var.key_pair_name) : var.resource_name
  effective_private_key_ssh           = var.private_key_ssh != "" ? var.private_key_ssh : tls_private_key.vm_ssh_key.private_key_pem
  effective_public_key_ssh            = var.public_key_ssh != "" ? var.public_key_ssh : tls_private_key.vm_ssh_key.public_key_openssh
  effective_vm_ssh_private_key_base64 = var.vm_ssh_private_key_base64 != "" ? var.vm_ssh_private_key_base64 : base64encode(tls_private_key.vm_ssh_key.private_key_pem)

  # Triggers for the null_resource, populated directly from generated or provided values
  vm_triggers = {
    node_id                   = random_id.node_id.hex
    instance_id               = random_id.instance_id.hex
    public_ip                 = "${var.public_ip_base}.${random_integer.public_ip_segment_4.result}"
    private_ip                = "${var.private_ip_base}.${random_integer.private_ip_segment_4.result}"
    key_pair_name             = local.effective_key_pair_name
    public_key_ssh            = local.effective_public_key_ssh
    private_key_ssh           = local.effective_private_key_ssh
    vm_ssh_private_key_base64 = local.effective_vm_ssh_private_key_base64
    vpc_id                    = random_id.vpc_id.hex
    public_subnet_id          = random_id.public_subnet_id.hex
    private_subnet_id         = random_id.private_subnet_id.hex
    state                     = local.mock_state
    type                      = local.mock_type
    az                        = local.mock_az
    timestamp                 = local.timestamp
  }
}

############################################################
# ── RESOURCES ─────────────────────────────────────────────
############################################################

# Generate a random ID for the node
resource "random_id" "node_id" {
  byte_length = 8
}

# Generate a random ID for the instance
resource "random_id" "instance_id" {
  byte_length = 8
}

# --- Resources for generating numeric Public IP address (last octet only) ---
resource "random_integer" "public_ip_segment_4" {
  min = 1
  max = 254
  keepers = {
    instance_name = var.resource_name
  }
}

# --- Resources for generating numeric Private IP address (last octet only) ---
resource "random_integer" "private_ip_segment_4" {
  min = 1
  max = 254
  keepers = {
    instance_name = var.resource_name
  }
}

# Generate a random string for the key pair name
resource "random_string" "key_pair_name" {
  length  = 10
  special = false
  upper   = false
  numeric = false
  keepers = {
    # Add a keeper to force recreation if resource_name changes
    instance_name = var.resource_name
  }
}

# Generate a random ID for the VPC
resource "random_id" "vpc_id" {
  byte_length = 8
}

# Generate a random ID for the public subnet
resource "random_id" "public_subnet_id" {
  byte_length = 8
}

# Generate a random ID for the private subnet
resource "random_id" "private_subnet_id" {
  byte_length = 8
}

# Generate a new SSH key pair
resource "tls_private_key" "vm_ssh_key" {
  algorithm = "RSA"
  rsa_bits  = 2048
}

# Save SSH private key to file
resource "local_file" "vm_ssh_private_key" {
  content         = local.effective_private_key_ssh
  filename        = "${path.module}/files/${var.key_pair_name}.pem"
  file_permission = "0644"
}

# Save SSH public key to file
resource "local_file" "vm_ssh_public_key" {
  content         = local.effective_public_key_ssh
  filename        = "${path.module}/files/${var.key_pair_name}.pub"
  file_permission = "0644"
}

# Save SSH private key content base64 encoded to file
resource "local_file" "vm_ssh_private_key_base64" {
  content         = local.effective_vm_ssh_private_key_base64
  filename        = "${path.module}/files/${var.key_pair_name}.pem.base64"
  file_permission = "0644"
}

resource "null_resource" "vm_instance" {
  triggers = local.vm_triggers
}

############################################################
# ── OUTPUTS ──────────────────────────────────────────────
############################################################
output "node_id" {
  value = null_resource.vm_instance.triggers.node_id
}

output "instance_id" {
  value = null_resource.vm_instance.triggers.instance_id
}

output "public_ip" {
  value = null_resource.vm_instance.triggers.public_ip
}

output "private_ip" {
  value = null_resource.vm_instance.triggers.private_ip
}

output "key_pair_name" {
  value = local.effective_key_pair_name
}

output "private_key_ssh" {
  value     = local.effective_private_key_ssh
  sensitive = true
}

output "public_key_ssh" {
  value = local.effective_public_key_ssh
}

output "vm_ssh_private_key_base64" {
  value     = local.effective_vm_ssh_private_key_base64
  sensitive = true
}

output "vpc_id" {
  value = null_resource.vm_instance.triggers.vpc_id
}

output "public_subnet_id" {
  value = null_resource.vm_instance.triggers.public_subnet_id
}

output "private_subnet_id" {
  value = null_resource.vm_instance.triggers.private_subnet_id
}

output "state" {
  value = null_resource.vm_instance.triggers.state
}

output "type" {
  value = null_resource.vm_instance.triggers.type
}

output "az" {
  value = null_resource.vm_instance.triggers.az
