-- Table Structure: tenants
CREATE TABLE IF NOT EXISTS "tenants" (
"id" VARCHAR(255) PRIMARY KEY,
"name" VARCHAR(255) NOT NULL,
"created_at" TIMESTAMP WITH TIME ZONE NOT NULL,
"updated_at" TIMESTAMP WITH TIME ZONE,
"is_active" BOOLEAN NOT NULL DEFAULT TRUE,
"tpm_limit" INTEGER DEFAULT 1000000,
"rpm_limit" INTEGER DEFAULT 100
);

-- No data for Table: tenants

-- Table Structure: models
CREATE TABLE IF NOT EXISTS "models" (
"id" VARCHAR(255) PRIMARY KEY,
"tenant_id" VARCHAR(255) NOT NULL,
"alias" VARCHAR(255) NOT NULL,
"model_path" VARCHAR(255) NOT NULL,
"state" VARCHAR(50) NOT NULL DEFAULT 'draft',
"source" VARCHAR(50) NOT NULL DEFAULT 'custom',
"model_type" VARCHAR(50) NOT NULL DEFAULT 'chat',
"version" VARCHAR(255) NOT NULL,
"description" TEXT,
"provider" VARCHAR(255),
"created_by" VARCHAR(255),
"created_at" TIMESTAMP WITH TIME ZONE NOT NULL,
"updated_at" TIMESTAMP WITH TIME ZONE,
"deleted_at" TIMESTAMP WITH TIME ZONE,
"is_deleted" BOOLEAN NOT NULL DEFAULT FALSE
);
CREATE INDEX IF NOT EXISTS "ix_models_tenant_id" ON "models" ("tenant_id");
CREATE INDEX IF NOT EXISTS "ix_models_alias" ON "models" ("alias");
CREATE INDEX IF NOT EXISTS "ix_models_state" ON "models" ("state");
CREATE INDEX IF NOT EXISTS "ix_models_source" ON "models" ("source");
CREATE INDEX IF NOT EXISTS "ix_models_model_type" ON "models" ("model_type");
CREATE INDEX IF NOT EXISTS "ix_models_is_deleted" ON "models" ("is_deleted");

-- No data for Table: models

-- Table Structure: model_metadata
CREATE TABLE IF NOT EXISTS "model_metadata" (
"id" VARCHAR(255) PRIMARY KEY,
"model_id" VARCHAR(255) NOT NULL UNIQUE,
"ui_config_version" VARCHAR(255) NOT NULL DEFAULT '1.0.0',
"ui_config" JSONB NOT NULL DEFAULT '{}',
"supports_streaming" BOOLEAN NOT NULL DEFAULT FALSE,
"supports_function_calling" BOOLEAN NOT NULL DEFAULT FALSE,
"max_tokens" INTEGER NOT NULL DEFAULT 2048,
"temperature_range" JSONB NOT NULL DEFAULT '{"min": 0.0, "max": 2.0}',
"prompt_fields" JSONB NOT NULL DEFAULT '[]',
"avg_latency_ms" DOUBLE PRECISION,
"avg_tokens_per_second" DOUBLE PRECISION,
"accuracy_score" DOUBLE PRECISION,
"created_at" TIMESTAMP WITH TIME ZONE NOT NULL,
"updated_at" TIMESTAMP WITH TIME ZONE
);

-- No data for Table: model_metadata

-- Table Structure: model_deployments (agent_control model deployments; pipeline "deployments" is separate)
CREATE TABLE IF NOT EXISTS "model_deployments" (
"id" VARCHAR(255) PRIMARY KEY,
"tenant_id" VARCHAR(255) NOT NULL,
"model_id" VARCHAR(255) NOT NULL,
"name" VARCHAR(255) NOT NULL,
"endpoint_url" VARCHAR(255) NOT NULL,
"region" VARCHAR(255) NOT NULL,
"status" VARCHAR(50) NOT NULL DEFAULT 'pending',
"tokens_used" INTEGER NOT NULL DEFAULT 0,
"requests_per_minute" DOUBLE PRECISION NOT NULL DEFAULT 0,
"cost_usd" DOUBLE PRECISION NOT NULL DEFAULT 0,
"created_at" TIMESTAMP WITH TIME ZONE NOT NULL,
"updated_at" TIMESTAMP WITH TIME ZONE,
"last_deployed_at" TIMESTAMP WITH TIME ZONE,
"is_custom" BOOLEAN NOT NULL DEFAULT FALSE,
"sku" VARCHAR(255),
"config" JSONB NOT NULL DEFAULT '{}'
);
CREATE INDEX IF NOT EXISTS "ix_model_deployments_tenant_id" ON "model_deployments" ("tenant_id");
CREATE INDEX IF NOT EXISTS "ix_model_deployments_model_id" ON "model_deployments" ("model_id");
CREATE INDEX IF NOT EXISTS "ix_model_deployments_status" ON "model_deployments" ("status");
CREATE INDEX IF NOT EXISTS "ix_model_deployments_tenant_status" ON "model_deployments" ("tenant_id", "status");

